// Board Pack (T-7, enriched): build the Anthropic Messages request from the
// app-computed figure set. The app sends ONLY the figures; this node turns them
// into a trace-to-data prompt. Every number the model may state comes from the
// figureSet's traceTable (ALLOWED NUMBERS) — which now also carries channel,
// conversion, pipeline-stage, retention and QoQ-trend figures, so the richer
// narrative below is still bound by the same zero-invention guarantee.
const NL = String.fromCharCode(10);
const inp = $input.first().json;
const b = inp.body || inp;
const fs = (b && b.figureSet) || {};
const M = fs.metrics || [];
const L = fs.levers || [];
const T = fs.traceTable || [];
const meta = fs.meta || {};
const channels = fs.channels || [];
const conversion = fs.conversion || [];
const ph = fs.pipelineHealth || {};
const ret = fs.retention || {};
const order = (meta.metricOrder || M.map(function (m) { return m.label; })).join(' -> ');

const mLines = M.map(function (m) {
  return m.order + '. ' + m.label + ': ' + m.valueDisplay +
    ' (target ' + m.targetDisplay + ', PROVISIONAL; status ' + m.status +
    (m.trend ? '; ' + m.trend.display : '') +
    (m.note ? '; ' + m.note : '') + ')';
}).join(NL);

const lLines = L.length
  ? L.map(function (l, i) {
      return (i + 1) + '. ' + l.title + ' - gap ' + l.gapDisplay +
        '; estimated pipeline impact ' + l.impactDisplay + ' (' + l.basis + ')';
    }).join(NL)
  : '(no open gaps in this scope)';

const cLines = channels.length
  ? channels.map(function (c) {
      return '- ' + c.channel + ': pipeline ' + c.pipelineDisplay +
        ' (' + c.pipelineShareDisplay + ' of total), ' + c.mqlDisplay +
        ' MQLs, closed-won ' + c.closedWonDisplay;
    }).join(NL)
  : '(no channel breakdown in this scope)';

const convAvail = conversion.filter(function (c) { return c.display && c.display !== 'n/a'; });
const convLines = convAvail.length
  ? convAvail.map(function (c) { return '- ' + c.from + ' -> ' + c.to + ': ' + c.display; }).join(NL)
  : '(conversion not available in this scope)';

const phLine = ph.hasData
  ? 'Open pipeline: ' + ph.openCountDisplay + ' opportunities worth ' + ph.openValueDisplay +
    '; probability-weighted forecast ' + ph.weightedDisplay +
    (ph.snapshotDate ? ' (snapshot ' + ph.snapshotDate + ', region-scoped current state, NOT a quarter slice)' : '') + '.'
  : '(no open-pipeline snapshot in this scope)';

const phStages = (ph.hasData && ph.stages && ph.stages.length)
  ? ph.stages.map(function (s) { return '- ' + s.stage + ': ' + s.countDisplay + ' opps, ' + s.valueDisplay; }).join(NL)
  : '';

const retLine = ret.hasData
  ? 'Retained contracts (won renewals): ' + ret.retainedCountDisplay + ' worth ' + ret.retainedValueDisplay +
    '. Expansion (upsell + cross-sell): ' + ret.expansionCountDisplay + ' worth ' + ret.expansionValueDisplay + '.'
  : '(no retention data in this scope)';

const allowed = T.map(function (t) { return '- ' + t.label + ': ' + t.display; }).join(NL);

const system = [
  'You write the executive board pack for CWSI, a B2B cybersecurity firm, from its marketing-intelligence dashboard.',
  'TRACE-TO-DATA RULES (absolute, non-negotiable):',
  '1) Use ONLY numbers that appear in FIGURES or ALLOWED NUMBERS below. Never invent, estimate, extrapolate, round to a new value, or calculate a new number. If a figure you want is not supplied, describe it qualitatively with no number.',
  '2) Quote every number in its exact displayed form (for example "GBP 612k" as shown, "17.5%", "+12% QoQ").',
  '3) Targets are PROVISIONAL placeholders - say a target is provisional whenever you cite one. If a metric actual is pending or shows n/a, say so; never fabricate it.',
  '4) Follow the agreed metric order: ' + order + '.',
  '5) The pipeline-stage snapshot is current-state and region-scoped, NOT a quarter slice - never describe it as a quarterly figure.',
  'Audience: the board and the CCO. Be specific and substantive: write each narrative section as a developed passage of 4 to 7 sentences (a full short paragraph), citing the relevant figures and the reasoning behind them, the so-what for the business, and what it implies for the decision at hand - detailed enough that the board can act on it, never one-line summaries. Return JSON only, matching the required schema.'
].join(NL);

const user = [
  'Scope: ' + (meta.regionLabel || 'All Regions') + ' | ' + (meta.quarterLabel || 'YTD') + ' | FY2026.',
  (meta.prevQuarterLabel ? 'QoQ trends compare against ' + meta.prevQuarterLabel + '.' : 'No prior in-scope quarter, so no QoQ trend is supplied.'),
  '',
  'FIGURES (metric: actual (target; status; QoQ trend)):',
  mLines,
  '',
  'FUNNEL CONVERSION (stage to stage):',
  convLines,
  '',
  'CHANNEL CONTRIBUTION (share of total pipeline):',
  cLines,
  '',
  'OPEN-PIPELINE HEALTH:',
  phLine,
  phStages,
  '',
  'RETENTION:',
  retLine,
  '',
  'GAPS TO CLOSE (ranked by estimated pipeline impact):',
  lLines,
  '',
  'ALLOWED NUMBERS (the only numbers you may state, with their exact display form):',
  allowed,
  '',
  'Produce:',
  '- narrative.onTrack: what is on or above (provisional) target, in the agreed metric order; cite QoQ trend where supplied.',
  '- narrative.behindAddressable: what is behind but addressable, citing the ranked levers and their estimated pipeline impact.',
  '- narrative.channelInsights: which channels are driving pipeline and MQLs and where the concentration or risk sits, citing channel shares. If no breakdown is supplied, say so briefly.',
  '- narrative.pipelineCommentary: read the open-pipeline health and probability-weighted forecast and what it implies for converting the quarter and H2. If no snapshot is supplied, say so briefly.',
  '- narrative.riskFlags: the data caveats the board should know - provisional targets, any pending/n-a metric, the MQL-date proxy, and that the pipeline snapshot is current-state not a quarter slice. Qualitative; cite a number only if it is in ALLOWED NUMBERS.',
  '- narrative.h2Plan: the H2 plan to close the gaps, highest-impact levers first.',
  '- recommendations[]: prioritised actions; each {title, rationale, estimatedImpact (use a lever impact figure where applicable, else "target pending"), metric (the board metric it moves)}.'
].join(NL);

const strProp = { type: 'string' };
const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    narrative: {
      type: 'object',
      additionalProperties: false,
      properties: {
        onTrack: strProp,
        behindAddressable: strProp,
        channelInsights: strProp,
        pipelineCommentary: strProp,
        riskFlags: strProp,
        h2Plan: strProp
      },
      required: ['onTrack', 'behindAddressable', 'channelInsights', 'pipelineCommentary', 'riskFlags', 'h2Plan']
    },
    recommendations: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          title: strProp,
          rationale: strProp,
          estimatedImpact: strProp,
          metric: strProp
        },
        required: ['title', 'rationale', 'estimatedImpact', 'metric']
      }
    }
  },
  required: ['narrative', 'recommendations']
};

return [{ json: { anthropicBody: {
  model: 'claude-opus-4-8',
  max_tokens: 16000,
  thinking: { type: 'adaptive' },
  system: system,
  messages: [{ role: 'user', content: user }],
  output_config: { effort: 'medium', format: { type: 'json_schema', schema: schema } }
} } }];

// Parse the Anthropic response. With adaptive thinking the content array may hold
// a thinking block before the text block, so pick the text block explicitly.
const res = $input.first().json;
const content = res.content || [];
let text = '';
for (const blk of content) { if (blk.type === 'text') { text = blk.text; break; } }
let parsed = {};
try { parsed = JSON.parse(text); } catch (e) { parsed = { _parseError: String(e), raw: text }; }
return [{ json: {
  narrative: parsed.narrative || {},
  recommendations: Array.isArray(parsed.recommendations) ? parsed.recommendations : [],
  model: res.model || 'claude-opus-4-8'
} }];
